package main

import (
	"context"
	"encoding/json"
	"fmt"
	"net"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// isBlockedIP checks if an IP address belongs to restricted ranges
// Blocks: loopback, private networks, link-local, unspecified, multicast
func isBlockedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Normalize IPv4-mapped IPv6 addresses
	if ipv4 := ip.To4(); ipv4 != nil {
		ip = ipv4
	}
	return ip.IsLoopback() || 
		ip.IsPrivate() || 
		ip.IsLinkLocalUnicast() || 
		ip.IsUnspecified() || 
		ip.IsMulticast()
}

// ConfigureWebhook handles POST requests to configure a webhook URL
// Security hardening:
// 1. SSRF protection via IP validation and DNS resolution checks
// 2. Rejects URLs with embedded credentials
// 3. Disables HTTP redirects to prevent redirect-based SSRF
// 4. Uses GET method for test request per requirements (no body)
// 5. Strict timeout controls for DNS and HTTP operations
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format and structure
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Enforce HTTP/S scheme only
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Reject URLs containing embedded credentials (prevents credential leakage and SSRF vectors)
	if parsedURL.User != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must not contain user credentials",
		})
	}

	// SSRF PROTECTION: Validate target host is not internal/reserved
	hostname := parsedURL.Hostname()

	// Case 1: Host is a literal IP address
	if ip := net.ParseIP(hostname); ip != nil {
		if isBlockedIP(ip) {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"success": false,
				"error":   "Webhook URL targets a restricted internal address",
			})
		}
	} else {
		// Case 2: Host is a domain name - resolve and validate all IPs
		resolver := &net.Resolver{}
		dnsCtx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
		defer cancel()

		ips, err := resolver.LookupIP(dnsCtx, "ip", hostname)
		if err != nil {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"success": false,
				"error":   "Failed to resolve webhook URL hostname",
			})
		}

		// Reject if ANY resolved IP is in restricted range
		for _, ip := range ips {
			if isBlockedIP(ip) {
				return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
					"success": false,
					"error":   "Webhook URL resolves to a restricted internal address",
				})
			}
		}
	}

	// Configure hardened HTTP client for test request
	client := &http.Client{
		Timeout: 3 * time.Second,
		// CRITICAL: Disable redirects to prevent SSRF via redirect chains
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Send GET test request (per requirements - no body for GET)
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Validate successful response (2xx status)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration (implementation depends on actual persistence layer)
	// Example: if err := db.SaveWebhookURL(req.WebhookURL); err != nil { ... }

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

