// Global configuration storage with mutex for thread safety
var (
	currentConfig struct {
		WebhookURL string
	}
	configMutex sync.Mutex
)

// ConfigureWebhook handles POST requests to configure and validate a webhook URL.
// Validates by sending a GET request with 3-second timeout, then saves configuration.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	type WebhookRequest struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON payload",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	testReq, err := http.NewRequest(http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Invalid webhook URL format: %v", err),
		})
	}

	resp, err := client.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook validation failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for 2xx success status codes only
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook returned non-2xx status: %d", resp.StatusCode),
		})
	}

	// Save configuration thread-safely
	configMutex.Lock()
	currentConfig.WebhookURL = req.WebhookURL
	configMutex.Unlock()

	return ctx.JSON(fiber.Map{
		"success":    true,
		"webhook_url": req.WebhookURL,
		"message":    "Webhook configured and validated successfully",
	})
}

func main() {
	app := fiber.New()

	// Register webhook configuration endpoint
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start server (error handling for production would be more robust)
	if err := app.Listen(":3000"); err != nil {
		panic(fmt.Sprintf("Failed to start server: %v", err))
	}
}

