// isUnsafeIP checks if an IP address belongs to non-routable or internal ranges
func isUnsafeIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Block loopback, private networks, link-local addresses, and unspecified addresses
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	// Block IPv4 unspecified and 0.0.0.0/8 range
	if ip.Equal(net.IPv4(0, 0, 0, 0)) || ip.Equal(net.IPv6unspecified) {
		return true
	}
	// Block remaining IPv4 0.0.0.0/8 addresses (e.g., 0.0.0.1)
	if ipv4 := ip.To4(); ipv4 != nil && ipv4[0] == 0 {
		return true
	}
	return false
}

// isHostSafe validates that a hostname does not resolve to internal/private IPs
func isHostSafe(ctx context.Context, host string) error {
	// Check if host is a literal IP address
	if ip := net.ParseIP(host); ip != nil {
		if isUnsafeIP(ip) {
			return fmt.Errorf("host is an unsafe IP address")
		}
		return nil
	}

	// Resolve domain name with context timeout
	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
	if err != nil {
		return fmt.Errorf("failed to resolve host: %w", err)
	}

	// Verify all resolved IPs are safe
	for _, ip := range ips {
		if isUnsafeIP(ip) {
			return fmt.Errorf("host resolves to unsafe IP address")
		}
	}
	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse JSON request body
