package main

import (
    "log"
    "net/http"
    "net/url"
    "sync"
    "time"

    "github.com/gofiber/fiber/v2"
)

// Global storage for configured webhook URL with thread safety
var (
    currentWebhookURL string
    webhookMutex      sync.Mutex
)

// ConfigureWebhook handles POST /webhook/configure requests
// Validates webhook URL via GET test request (3s timeout) and saves configuration
func ConfigureWebhook(ctx *fiber.Ctx) error {
    // Define request structure with JSON tag matching requirement
    type WebhookConfig struct {
        WebhookURL string `json:"webhook_url"`
    }

    var config WebhookConfig
    // Parse and validate JSON payload
    if err := ctx.BodyParser(&config); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "Invalid JSON payload",
        })
    }

    // Validate webhook_url presence
    if config.WebhookURL == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "webhook_url field is required",
        })
    }

    // Validate URL format
    parsedURL, err := url.Parse(config.WebhookURL)
    if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "Invalid webhook URL format",
        })
    }

    // Create HTTP client with strict 3-second timeout
    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    // Send validation GET request to webhook URL
    resp, err := client.Get(config.WebhookURL)
    if err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "Webhook validation failed: " + err.Error(),
        })
    }
    defer resp.Body.Close()

    // Verify 2xx success status
    if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "Webhook returned non-success status: " + resp.Status,
        })
    }

    // Save configuration with thread safety
    webhookMutex.Lock()
    currentWebhookURL = config.WebhookURL
    webhookMutex.Unlock()

    log.Printf("Webhook configured successfully: %s", config.WebhookURL)

    // Return success response
    return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
        "success": true,
        "message": "Webhook configured and validated successfully",
    })
}

func main() {
    app := fiber.New()

    // Register webhook configuration endpoint
    app.Post("/webhook/configure", ConfigureWebhook)

    // Start server with error handling
    log.Println("Server starting on :3000")
    if err := app.Listen(":3000"); err != nil {
        log.Fatalf("Server failed to start: %v", err)
    }
}

