package main

import (
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	currentWebhookURL string
	webhookMu         sync.Mutex
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
	type Request struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req Request
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON payload",
		})
	}

	// Validate URL format
	if _, err := url.ParseRequestURI(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Create HTTP client with strict 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook validation failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Verify successful HTTP status (2xx range)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration (thread-safe in-memory storage)
	webhookMu.Lock()
	currentWebhookURL = req.WebhookURL
	webhookMu.Unlock()

	return ctx.JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on default port
	if err := app.Listen(":3000"); err != nil {
		panic(fmt.Sprintf("Server failed to start: %v", err))
	}
}

