package main

import (
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest represents the expected JSON payload
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Global storage for configured webhook with mutex for thread safety
var (
	webhookMu      sync.Mutex
	currentWebhook string
)

// ConfigureWebhook handles POST requests to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse JSON request body
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON payload",
		})
	}

	// Validate webhook_url is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url field is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format (must include scheme and host)",
		})
	}

	// Create HTTP client with 3-second timeout for validation request
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send validation GET request to webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook validation failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Verify response status is 2xx
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration with thread safety
	webhookMu.Lock()
	currentWebhook = req.WebhookURL
	webhookMu.Unlock()

	// Return success response
	return ctx.JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured and validated successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Register webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server (handle startup error)
	if err := app.Listen(":3000"); err != nil {
		panic(fmt.Errorf("server failed to start: %w", err))
	}
}

