			"success": false,
			"error":   fmt.Sprintf("Webhook test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Validate webhook returned successful HTTP status (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration (implementation depends on application architecture)
