package main

import (
	"fmt"
	"log"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	configuredWebhook string
	webhookMutex      sync.Mutex
	testClient        = &http.Client{Timeout: 3 * time.Second}
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON payload
	type webhookRequest struct {
		WebhookURL string `json:"webhook_url"`
	}
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON payload",
		})
	}

	// Validate webhook URL format
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format (must include scheme and host)",
		})
	}

	// Send test GET request to webhook URL
	testReq, err := http.NewRequestWithContext(ctx.Context(), "GET", req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	resp, err := testClient.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to reach webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Validate response status code (must be 2xx)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration with thread safety
	webhookMutex.Lock()
	configuredWebhook = req.WebhookURL
	webhookMutex.Unlock()

	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"url":     req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Register webhook configuration endpoint
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start server
	log.Println("Starting server on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatal("Server failed to start:", err)
	}
}

