package main

import (
	"fmt"
	"io"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	currentWebhookURL string
	webhookMutex      sync.Mutex
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Define input structure
	type WebhookInput struct {
		WebhookURL string `json:"webhook_url"`
	}

	// Parse JSON body
	var input WebhookInput
	if err := ctx.BodyParser(&input); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	// Validate webhook_url is not empty
	if input.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required and cannot be empty",
		})
	}

	// Validate URL format
	parsedURL, err := url.Parse(input.WebhookURL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format. Must be a valid URL with scheme and host",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to webhook URL
	resp, err := client.Get(input.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Test request failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Discard response body to ensure proper connection cleanup
	_, _ = io.Copy(io.Discard, resp.Body)

	// Validate response status code is in 2xx range
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration with thread safety
	webhookMutex.Lock()
	currentWebhookURL = input.WebhookURL
	webhookMutex.Unlock()

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook URL validated and configured successfully",
	})
}

func main() {
	app := fiber.New()
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000 (error handling for production would be more robust)
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

