// isUnsafeIP checks if an IP address belongs to unsafe ranges (loopback, private, link-local, multicast, etc.)
func isUnsafeIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Block standard unsafe categories using stdlib checks
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() {
		return true
	}
	// IPv4-specific private ranges
	if ipv4 := ip.To4(); ipv4 != nil {
		// RFC 1918 private ranges
		if ipv4[0] == 10 {
			return true
		}
		if ipv4[0] == 172 && ipv4[1] >= 16 && ipv4[1] <= 31 {
			return true
		}
		if ipv4[0] == 192 && ipv4[1] == 168 {
			return true
		}
		// RFC 6598 Carrier-Grade NAT
		if ipv4[0] == 100 && ipv4[1] >= 64 && ipv4[1] <= 127 {
			return true
		}
		return false
	}
	// IPv6 Unique Local Addresses (RFC 4193): fc00::/7
	if len(ip) == 16 && (ip[0] == 0xfc || ip[0] == 0xfd) {
		return true
	}
	return false
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format and structure
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure scheme is http or https
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// SSRF PROTECTION: Validate target is not internal/reserved
	hostname := parsedURL.Hostname()

	// Check if hostname is a literal IP address
	if ip := net.ParseIP(hostname); ip != nil {
		if isUnsafeIP(ip) {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"success": false,
				"error":   "Webhook URL targets an internal or reserved network address",
			})
		}
	} else {
		// Resolve hostname to IPs and validate each
		ips, err := net.LookupIP(hostname)
		if err != nil {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"success": false,
				"error":   "Failed to resolve webhook hostname",
			})
		}
		for _, ip := range ips {
			if isUnsafeIP(ip) {
				return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
					"success": false,
					"error":   "Webhook URL resolves to an internal or reserved network address",
				})
			}
		}
	}

	// Create hardened HTTP client
	client := &http.Client{
		Timeout: 3 * time.Second,
		// Prevent SSRF via open redirects
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse // Return redirect response without following
		},
	}

	// Send GET test request (no body per requirement)
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Validate successful response (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration (implementation depends on actual persistence layer)
	// db.SaveWebhookURL(req.WebhookURL)

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

