	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsPrivate() || ip.IsUnspecified() {
		return true
	}
	// Explicitly block IPv4 link-local (169.254.0.0/16) for environments where IsLinkLocalUnicast may not cover all cases
	if v4 := ip.To4(); v4 != nil {
		linkLocalBlock := net.IPNet{
			IP:   net.IP{169, 254, 0, 0},
			Mask: net.CIDRMask(16, 32),
		}
		if linkLocalBlock.Contains(v4) {
			return true
		}
	}
	return false
}

// ConfigureWebhook handles POST requests to configure a webhook URL
// Security hardening:
// 1. SSRF protection via IP resolution and blocklist validation
// 2. Redirects disabled to prevent SSRF via redirection chains
// 3. Strict IP validation (loopback, link-local, private ranges, metadata endpoints)
// 4. GET method used per requirement (no payload sent)
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format and structure
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Enforce HTTP/S scheme only
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// SSRF PROTECTION: Resolve and validate all IPs associated with the host
	host := parsedURL.Hostname()
	ips, err := net.LookupIP(host)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to resolve webhook URL host",
		})
	}

	// Reject if ANY resolved IP is in blocked range (defense against DNS rebinding)
	for _, ip := range ips {
		if isBlockedIP(ip) {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"success": false,
				"error":   "webhook URL resolves to internal/reserved IP address (SSRF protection)",
			})
		}
	}

	// Configure HTTP client with security constraints
	client := &http.Client{
		Timeout: 3 * time.Second,
		// CRITICAL: Disable redirects to prevent SSRF via redirection chains
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse // Return redirect response without following
		},
	}

	// Send TEST GET REQUEST (per requirement) - no payload sent with GET
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test GET request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Validate webhook responded with success status (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration (implementation depends on actual persistence layer)
	// db.SaveWebhookURL(req.WebhookURL) // Example placeholder

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

