// ConfigureWebhook handles POST requests to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	type request struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req request
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON payload",
		})
	}

	webhookURL := strings.TrimSpace(req.WebhookURL)
	if webhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url cannot be empty",
		})
	}

	// Validate URL structure
	parsedURL, err := url.Parse(webhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid URL format: " + err.Error(),
		})
	}
	if parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "URL must contain scheme (http/https) and host",
		})
	}

	// Create HTTP client with 3-second timeout for validation
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to webhook URL
	resp, err := client.Get(webhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Verify successful HTTP status (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook returned non-success status: " + resp.Status,
		})
	}

	// Save configuration (thread-safe)
	webhookMutex.Lock()
	currentWebhookURL = webhookURL
	webhookMutex.Unlock()

	return ctx.JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": webhookURL,
	})
}

func main() {
	app := fiber.New()

	// Register webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatal(err)
	}
}

