// loopback, link-local (unicast/multicast), private networks, or unspecified addresses.
// Requires Go 1.17+ for IP.IsPrivate() support.
func isUnsafeIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
		return true
	}
	return ip.IsPrivate()
}

