package main

import (
	"fmt"
	"net"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// isIPBlocked checks if an IP address belongs to restricted ranges
// Blocks: loopback, private networks, link-local addresses, multicast, and unspecified addresses
func isIPBlocked(ip net.IP) bool {
	if ip == nil {
		return true
	}
	if ip.IsLoopback() || 
	   ip.IsPrivate() || 
	   ip.IsLinkLocalUnicast() || 
	   ip.IsLinkLocalMulticast() || 
	   ip.IsMulticast() || 
	   ip.IsUnspecified() {
		return true
	}
	// Additional explicit checks for robustness
	if ipv4 := ip.To4(); ipv4 != nil {
		// Block 0.0.0.0 explicitly
		if ipv4.Equal(net.IPv4(0, 0, 0, 0)) {
			return true
		}
	}
	return false
}

// ConfigureWebhook handles POST requests to configure a webhook URL
// Security hardening:
// 1. Blocks SSRF via IP range validation after DNS resolution
// 2. Rejects URLs with credentials
// 3. Disables HTTP redirects to prevent redirect-based SSRF
// 4. Uses GET method per requirements (no body)
// 5. Strict timeout enforcement
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format and structure
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Block URLs containing credentials (SSRF/user leakage risk)
	if parsedURL.User != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL must not contain user credentials",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Extract hostname for DNS resolution (handles IPv4/IPv6 literals)
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL host cannot be empty",
		})
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to resolve webhook hostname: %v", err),
		})
	}

	// Validate all resolved IPs against restricted ranges
	for _, ip := range ips {
		if isIPBlocked(ip) {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"success": false,
				"error":   "Webhook URL resolves to a restricted internal address",
			})
		}
	}

	// Configure hardened HTTP client
	client := &http.Client{
		Timeout: 3 * time.Second,
		// Prevent redirect-based SSRF attacks
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Send GET test request (per requirements - no body)
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Verify successful response (2xx status)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration (implementation depends on application)
	// Example: if err := db.SaveWebhookURL(req.WebhookURL); err != nil { ... }

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

