import (
    "fmt"
    "net/http"
    "net/url"
    "sync"
    "time"

    "github.com/gofiber/fiber/v2"
)

var (
    savedWebhookURL string
    webhookMu       sync.Mutex
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
    type WebhookRequest struct {
        WebhookURL string `json:"webhook_url"`
    }

    var req WebhookRequest
    if err := ctx.BodyParser(&req); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "message": "Invalid JSON payload",
        })
    }

    if req.WebhookURL == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "message": "webhook_url is required",
        })
    }

    parsedURL, err := url.Parse(req.WebhookURL)
    if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "message": "Invalid webhook URL format",
        })
    }

    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    resp, err := client.Get(req.WebhookURL)
    if err != nil {
        return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
            "success": false,
            "message": fmt.Sprintf("Webhook validation failed: %v", err),
        })
    }
    defer resp.Body.Close()

    if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
        return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
            "success": false,
            "message": fmt.Sprintf("Webhook returned non-2xx status: %d", resp.StatusCode),
        })
    }

    webhookMu.Lock()
    savedWebhookURL = req.WebhookURL
    webhookMu.Unlock()

    return ctx.JSON(fiber.Map{
        "success": true,
        "message": "Webhook configured successfully",
    })
}

func main() {
    app := fiber.New()
    app.Post("/configure-webhook", ConfigureWebhook)

    if err := app.Listen(":3000"); err != nil {
        panic(fmt.Sprintf("Server failed to start: %v", err))
    }
}

