package main

import (
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	currentWebhookURL string
	webhookMutex      sync.Mutex
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var req struct {
		WebhookURL string `json:"webhook_url"`
	}
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "invalid JSON body",
		})
	}

	// Validate webhook_url presence
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "invalid webhook URL format",
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url must use HTTP or HTTPS scheme",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("failed to reach webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Validate response status code (must be 2xx)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success":    false,
			"error":      "webhook URL returned non-success status code",
			"status_code": resp.StatusCode,
		})
	}

	// Save configuration (thread-safe)
	webhookMutex.Lock()
	currentWebhookURL = req.WebhookURL
	webhookMutex.Unlock()

	// Return success response
	return ctx.JSON(fiber.Map{
		"success":     true,
		"webhook_url": req.WebhookURL,
		"message":     "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server (port 3000)
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

