package main

import (
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	currentWebhookURL string
	webhookMu         sync.Mutex
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse JSON request body
	var requestBody struct {
		WebhookURL string `json:"webhook_url"`
	}
	if err := ctx.BodyParser(&requestBody); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON body",
		})
	}

	// Validate webhook_url is not empty
	if requestBody.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(requestBody.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to webhook URL
	resp, err := client.Get(requestBody.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Verify successful HTTP status (2xx)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration thread-safely
	webhookMu.Lock()
	currentWebhookURL = requestBody.WebhookURL
	webhookMu.Unlock()

	// Return success response
	return ctx.JSON(fiber.Map{
		"success":     true,
		"webhook_url": requestBody.WebhookURL,
		"message":     "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()
	app.Post("/webhook", ConfigureWebhook)

	// Start server (error handling for demonstration)
	if err := app.Listen(":3000"); err != nil {
		panic(fmt.Errorf("server failed: %w", err))
	}
}

